#include "Book.h"#include <iomanip>using namespace std;string Book::getTitle() const {    return title;}string Book::getAuthor() const {    return author;}string Book::getCopyrightDate() const {    return copyrightDate;}void Book::setTitle(string title) {    this->title = title;}void Book::setAuthor(string author) {    this->author = author;}void Book::setCopyrightDate(string copyrightDate) {    this->copyrightDate = copyrightDate;}void Book::print(ostream &out) const {    const int LABEL_WIDTH = 15; // "Copyright Date" is the longest label    out << left << setw(LABEL_WIDTH) << "Item Type"      << ": Book" << endl;    out << left << setw(LABEL_WIDTH) << "Name"           << ": " << getName() << endl;    out << left << setw(LABEL_WIDTH) << "Description"    << ": " << getDescription() << endl;    out << left << setw(LABEL_WIDTH) << "ID"             << ": " << getId() << endl;    out << left << setw(LABEL_WIDTH) << "Title"          << ": " << title << endl;    out << left << setw(LABEL_WIDTH) << "Author"         << ": " << author << endl;    out << left << setw(LABEL_WIDTH) << "Copyright Date" << ": " << copyrightDate << endl;    if (isCheckedOut()) {        out << left << setw(LABEL_WIDTH) << "Status"      << ": Checked Out" << endl;        out << left << setw(LABEL_WIDTH) << "Borrowed By" << ": " << getBorrowName() << endl;        out << left << setw(LABEL_WIDTH) << "Due Date"    << ": " << getDueDate() << endl;    }    else {        out << left << setw(LABEL_WIDTH) << "Status" << ": Available" << endl;    }}